import yaml
from io import StringIO

def load_config_yaml(yaml_path):
    # Validate input to prevent path traversal and ensure existence
    if not os.path.isfile(yaml_path):
        raise FileNotFoundError(f"The specified YAML file {yaml_path} does not exist.")

    with open(yaml_path, 'r') as file:
        config_data = yaml.safe_load(file)

    return config_data

def load_config_env(config_data):
    env_vars = {}
    for key, value in config_data.items():
        if isinstance(value, (str, int, float)):
            # Ensure environment variables are properly escaped
            env_var_value = os.environ.get(key) or str(value)
            env_vars[key] = f"{os.getenv(key)}={env_var_value}" if env_var_value else env_var_value

    return env_vars

def main(yaml_path):
    config_data = load_config_yaml(yaml_path)
    sanitized_env_vars = load_config_env(config_data)

    # Output or use the environment variables
    for key, value in sanitized_env_vars.items():
        print(f"Environment variable {key} set to: {value}")

if __name__ == "__main__":
    YAML_FILE_PATH = 'path/to/your/config.yaml'
    main(YAML_FILE_PATH)
