from django import template
import yaml

register = template.Library()

class SafeLoader(yaml.Loader):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.add_constructor(
            '!safeyaml',
            lambda loader, node: loader.construct_yaml_str(node).encode('ascii', 'backslashreplace')
        )

@register.tag(name='secure_yaml_load')
def do_secure_yaml(parser, token):
    tag_name, filename = token.split_contents()
    if len(token.split_contents()) != 2:
        raise template.TemplateSyntaxError(f"{tag_name} takes exactly one argument.")
    return SafeYamlNode(filename)

class SafeYamlNode(template.Node):
    def __init__(self, filename):
        self.filename = filename

    def render(self, context):
        with open(context['request'].build_absolute_uri(self.filename), 'r') as file:
            config_data = yaml.load(file, Loader=SafeLoader)
            return str(yaml.safe_dump(config_data, default_flow_style=False))

